import java.util.*;

public class Main {
    public static void main(String[] args) {
        FoodDeliverySystem sys = new FoodDeliverySystem();
        Restaurant r = new Restaurant("R1", "Pizza", "1 St", 40.0, -74.0);
        r.addMenuItem(new MenuItem("M1", "Pizza", "Cheese", 10.00));
        r.addMenuItem(new MenuItem("M2", "Cola", "330ml", 2.00));
        sys.registerRestaurant(r);
        DeliveryAgent a = new DeliveryAgent("A1", "Mike", 40.001, -74.001);
        sys.registerAgent(a);
        Customer c = new Customer("C1", "Alice", "a@e", "555", "Addr", 40.05, -74.05);
        CommandInvoker inv = new CommandInvoker();
        Map<MenuItem, Integer> items = new LinkedHashMap<>();
        items.put(r.getMenu().get(0), 2);
        items.put(r.getMenu().get(1), 1);
        PlaceOrderCommand cmd = new PlaceOrderCommand(sys, c, r, items);
        inv.run(cmd);
        Order o = cmd.getPlacedOrder();
        if (o == null) { System.out.println("FAIL_PLACE"); return; }
        if (Math.abs(o.getTotalAmount() - 22.0) < 0.01 && o.getState() == OrderState.PLACED) System.out.println("PLACE_OK");
        else System.out.println("PLACE_FAIL");
    }
}

